 21→// ItemContentUpdater updates worker-managed fields on items.
 22→type ItemContentUpdater interface {
 23→	UpdateContent(ctx context.Context, itemID uuid.UUID, input item.ContentUpdate) error
 24→}
 25→
 26→const (
 27→	fetchTimeout = 30 * time.Second
 28→	userAgent    = "Flotsam/1.0 (bookmark fetcher)"
 29→)
