 31→// PageFetchArgs are the arguments for a page fetch job.
 32→type PageFetchArgs struct {
 33→	ItemID uuid.UUID `json:"item_id"`
 34→	URL    string    `json:"url"`
 35→}
 36→
 37→func (PageFetchArgs) Kind() string { return "page_fetch" }
 38→
 39→// PageFetchWorker fetches and extracts readable content from bookmark URLs.
 40→type PageFetchWorker struct {
 41→	river.WorkerDefaults[PageFetchArgs]
 42→	Items       ItemContentUpdater
 43→	Storage     *storage.Client        // nil if S3 not configured
 44→	Client      *http.Client           // nil uses SSRF-safe client
 45→	SafeClient  *safefetch.Client      // nil uses default safefetch client
 46→	RiverClient *river.Client[pgx.Tx]  // for enqueuing follow-up jobs (embed)
 47→}
 48→
 49→func (w *PageFetchWorker) safeClient() *safefetch.Client {
 50→	if w.SafeClient != nil {
 51→		return w.SafeClient
 52→	}
 53→	return safefetch.NewClient()
 54→}
 55→
 56→func (w *PageFetchWorker) Work(ctx context.Context, job *river.Job[PageFetchArgs]) error {
 57→	itemID := job.Args.ItemID
 58→	url := job.Args.URL
 59→
 60→	slog.InfoContext(ctx, "worker: page_fetch: processing",
 61→		"item_id", itemID,
 62→		"url", url,
 63→	)
 64→
 65→	// Mark item as processing
 66→	if err := w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "processing"}); err != nil {
 67→		return fmt.Errorf("worker: page_fetch: set processing: %w", err)
 68→	}
 69→
 70→	// Fetch and extract content
 71→	article, err := w.fetchAndExtract(ctx, url)
 72→	if err != nil {
 73→		// Set item to error status
 74→		_ = w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "error"})
 75→		return fmt.Errorf("worker: page_fetch: fetch: %w", err)
 76→	}
 77→
 78→	// Upload HTML to S3 if storage is configured
 79→	var contentURL *string
 80→	if w.Storage != nil && article.Content != "" {
 81→		key := fmt.Sprintf("items/%s/page.html", itemID)
 82→		if err := w.Storage.Upload(ctx, key, strings.NewReader(article.Content), "text/html"); err != nil {
 83→			slog.ErrorContext(ctx, "worker: page_fetch: s3 upload failed, continuing without",
 84→				"item_id", itemID,
 85→				"error", err,
 86→			)
 87→		} else {
 88→			contentURL = &key
 89→		}
 90→	}
 91→
 92→	// Build content update
 93→	update := item.ContentUpdate{Status: "ready"}
 94→	if article.Title != "" {
 95→		update.Title = &article.Title
 96→	}
 97→	if article.TextContent != "" {
 98→		update.ContentText = &article.TextContent
 99→	}
100→	if contentURL != nil {
101→		update.ContentURL = contentURL
102→	}
103→
104→	if err := w.Items.UpdateContent(ctx, itemID, update); err != nil {
105→		return fmt.Errorf("worker: page_fetch: update item: %w", err)
106→	}
107→
108→	slog.InfoContext(ctx, "worker: page_fetch: done",
109→		"item_id", itemID,
110→		"title", article.Title,
111→		"text_length", len(article.TextContent),
112→	)
113→
114→	// Enqueue embedding job if content was extracted
115→	if article.TextContent != "" {
116→		w.enqueueEmbed(ctx, itemID, article.TextContent)
117→	}
118→
119→	return nil
120→}
121→
122→type fetchResult struct {
123→	Title       string
124→	TextContent string
125→	Content     string // HTML content
126→}
127→
128→func (w *PageFetchWorker) fetchAndExtract(ctx context.Context, url string) (*fetchResult, error) {
129→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
130→	if err != nil {
131→		return nil, fmt.Errorf("build request: %w", err)
132→	}
133→	req.Header.Set("User-Agent", userAgent)
134→
135→	// Use SSRF-safe client if no test client is injected
136→	var resp *http.Response
137→	if w.Client != nil {
138→		resp, err = w.Client.Do(req)
139→	} else {
140→		resp, err = w.safeClient().Do(ctx, req)
141→	}
142→	if err != nil {
143→		return nil, fmt.Errorf("http get: %w", err)
144→	}
145→	defer func() { _ = resp.Body.Close() }()
146→
147→	if resp.StatusCode >= 400 {
148→		return nil, fmt.Errorf("http status %d for %s", resp.StatusCode, url)
149→	}
150→
151→	article, err := readability.FromReader(resp.Body, nil)
152→	if err != nil {
153→		return nil, fmt.Errorf("readability parse: %w", err)
154→	}
155→
156→	return &fetchResult{
157→		Title:       article.Title,
158→		TextContent: article.TextContent,
159→		Content:     article.Content,
160→	}, nil
161→}
162→
163→func (w *PageFetchWorker) enqueueEmbed(ctx context.Context, itemID uuid.UUID, content string) {
164→	if w.RiverClient == nil {
165→		return
166→	}
167→	_, err := w.RiverClient.Insert(ctx, &EmbedArgs{
168→		ItemID:  itemID,
169→		Content: content,
170→	}, nil)
171→	if err != nil {
172→		slog.ErrorContext(ctx, "worker: page_fetch: failed to enqueue embed job",
173→			"item_id", itemID,
174→			"error", err,
175→		)
176→	}
177→}
