 18→const (
 19→	// DefaultTimeout is the default HTTP client timeout.
 20→	DefaultTimeout = 30 * time.Second
 21→
 22→	// DefaultMaxResponseBytes is the maximum response body size (10 MB).
 23→	DefaultMaxResponseBytes = 10 * 1024 * 1024
 24→
 25→	// maxRedirects is the maximum number of redirects to follow.
 26→	maxRedirects = 10
 27→)
 28→
 29→// allowedSchemes are the only URL schemes permitted for fetching.
 30→var allowedSchemes = map[string]bool{
 31→	"http":  true,
 32→	"https": true,
 33→}
 34→
 35→// blockedNets are CIDR ranges that must never be fetched.
 36→var blockedNets []*net.IPNet
 37→
 38→func init() {
 39→	cidrs := []string{
 40→		"127.0.0.0/8",    // IPv4 loopback
 41→		"10.0.0.0/8",     // RFC 1918
 42→		"172.16.0.0/12",  // RFC 1918
 43→		"192.168.0.0/16", // RFC 1918
 44→		"169.254.0.0/16", // link-local
 45→		"0.0.0.0/8",      // unspecified / "this" network
 46→		"100.64.0.0/10",  // shared address space (CGNAT)
 47→		"192.0.0.0/24",   // IETF protocol assignments
 48→		"192.0.2.0/24",   // TEST-NET-1
 49→		"198.51.100.0/24", // TEST-NET-2
 50→		"203.0.113.0/24", // TEST-NET-3
 51→		"224.0.0.0/4",    // multicast
 52→		"240.0.0.0/4",    // reserved
 53→		"::1/128",        // IPv6 loopback
 54→		"fc00::/7",       // IPv6 unique local
 55→		"fe80::/10",      // IPv6 link-local
 56→		"ff00::/8",       // IPv6 multicast
 57→		"::/128",         // IPv6 unspecified
 58→	}
 59→	for _, cidr := range cidrs {
 60→		_, ipNet, err := net.ParseCIDR(cidr)
 61→		if err != nil {
 62→			panic(fmt.Sprintf("safefetch: invalid CIDR %q: %v", cidr, err))
 63→		}
 64→		blockedNets = append(blockedNets, ipNet)
 65→	}
 66→}
