 68→// allowedContentTypes are Content-Type prefixes we accept.
 69→var allowedContentTypes = []string{
 70→	"text/",
 71→	"application/xhtml",
 72→	"application/xml",
 73→	"application/json",
 74→}
 75→
 76→var (
 77→	// ErrBlockedScheme is returned when the URL uses a non-HTTP(S) scheme.
 78→	ErrBlockedScheme = errors.New("safefetch: blocked scheme")
 79→
 80→	// ErrBlockedIP is returned when the resolved IP is in a blocked range.
 81→	ErrBlockedIP = errors.New("safefetch: blocked IP address")
 82→
 83→	// ErrBlockedContentType is returned when the response Content-Type is not allowed.
 84→	ErrBlockedContentType = errors.New("safefetch: blocked content type")
 85→
 86→	// ErrTooManyRedirects is returned when the redirect limit is exceeded.
 87→	ErrTooManyRedirects = errors.New("safefetch: too many redirects")
 88→
 89→	// ErrEmptyHost is returned when the URL has no hostname.
 90→	ErrEmptyHost = errors.New("safefetch: empty host")
 91→)
