 93→// Resolver resolves hostnames to IP addresses. Matches net.Resolver.LookupIPAddr.
 94→type Resolver interface {
 95→	LookupIPAddr(ctx context.Context, host string) ([]net.IPAddr, error)
 96→}
 97→
 98→// Option configures a Client.
 99→type Option func(*Client)
100→
101→// WithResolver overrides the DNS resolver (useful for testing).
102→func WithResolver(r Resolver) Option {
103→	return func(c *Client) { c.resolver = r }
104→}
105→
106→// WithMaxResponseBytes overrides the response body size cap.
107→func WithMaxResponseBytes(n int64) Option {
108→	return func(c *Client) { c.maxResponseBytes = n }
109→}
110→
111→// WithTransport sets the base HTTP transport (useful for testing with httptest).
112→func WithTransport(t http.RoundTripper) Option {
113→	return func(c *Client) { c.baseTransport = t }
114→}
115→
116→// Client is an SSRF-safe HTTP client.
117→type Client struct {
118→	resolver         Resolver
119→	maxResponseBytes int64
120→	baseTransport    http.RoundTripper
121→}
122→
123→// NewClient creates a new SSRF-safe HTTP client.
124→func NewClient(opts ...Option) *Client {
125→	c := &Client{
126→		resolver:         net.DefaultResolver,
127→		maxResponseBytes: DefaultMaxResponseBytes,
128→		baseTransport:    http.DefaultTransport,
129→	}
130→	for _, opt := range opts {
131→		opt(c)
132→	}
133→	return c
134→}
135→
136→// Do performs an SSRF-safe HTTP request. It validates the URL scheme, resolves
137→// DNS, checks all resolved IPs against blocked ranges, pins the connection to
138→// the resolved IP, follows redirects safely, and caps the response body size.
139→func (c *Client) Do(ctx context.Context, req *http.Request) (*http.Response, error) {
140→	redirectCount := 0
141→
142→	for {
143→		// Validate scheme
144→		if !allowedSchemes[req.URL.Scheme] {
145→			return nil, fmt.Errorf("%w: %s", ErrBlockedScheme, req.URL.Scheme)
146→		}
147→
148→		// Resolve and validate the target IP
149→		host := req.URL.Hostname()
150→		if host == "" {
151→			return nil, ErrEmptyHost
152→		}
153→
154→		ip, err := c.resolveAndValidate(ctx, host)
155→		if err != nil {
156→			return nil, err
157→		}
158→
159→		// Use pinned transport in production; use injected transport for tests
160→		var transport http.RoundTripper
161→		if c.baseTransport != http.DefaultTransport {
162→			transport = c.baseTransport
163→		} else {
164→			transport = c.pinnedTransport(ip, req.URL.Port())
165→		}
166→
167→		// Disable automatic redirects — we handle them manually to re-validate IPs
168→		client := &http.Client{
169→			Transport: transport,
170→			Timeout:   DefaultTimeout,
171→			CheckRedirect: func(_ *http.Request, _ []*http.Request) error {
172→				return http.ErrUseLastResponse
173→			},
174→		}
175→
176→		resp, err := client.Do(req)
177→		if err != nil {
178→			return nil, fmt.Errorf("safefetch: http: %w", err)
179→		}
180→
181→		// Handle redirects manually
182→		if isRedirect(resp.StatusCode) {
183→			_ = resp.Body.Close()
184→			redirectCount++
185→			if redirectCount > maxRedirects {
186→				return nil, ErrTooManyRedirects
187→			}
188→
189→			loc := resp.Header.Get("Location")
190→			if loc == "" {
191→				return nil, fmt.Errorf("safefetch: redirect with no Location header")
192→			}
193→
194→			redirectURL, err := req.URL.Parse(loc)
195→			if err != nil {
196→				return nil, fmt.Errorf("safefetch: invalid redirect URL: %w", err)
197→			}
198→
199→			req, err = http.NewRequestWithContext(ctx, http.MethodGet, redirectURL.String(), nil)
200→			if err != nil {
201→				return nil, fmt.Errorf("safefetch: build redirect request: %w", err)
202→			}
203→			continue
204→		}
205→
206→		// Validate content type
207→		ct := resp.Header.Get("Content-Type")
208→		if ct != "" && !isAllowedContentType(ct) {
209→			_ = resp.Body.Close()
210→			return nil, fmt.Errorf("%w: %s", ErrBlockedContentType, ct)
211→		}
212→
213→		// Cap response body size
214→		resp.Body = io.NopCloser(io.LimitReader(resp.Body, c.maxResponseBytes))
215→		return resp, nil
216→	}
217→}
218→
219→// ValidateURL checks a URL string for SSRF safety without making a request.
220→func (c *Client) ValidateURL(ctx context.Context, rawURL string) error {
221→	u, err := url.Parse(rawURL)
222→	if err != nil {
223→		return fmt.Errorf("safefetch: invalid URL: %w", err)
224→	}
225→	if !allowedSchemes[u.Scheme] {
226→		return fmt.Errorf("%w: %s", ErrBlockedScheme, u.Scheme)
227→	}
228→	host := u.Hostname()
229→	if host == "" {
230→		return ErrEmptyHost
231→	}
232→	_, err = c.resolveAndValidate(ctx, host)
233→	return err
234→}
235→
236→// resolveAndValidate resolves a hostname and checks all IPs against blocked ranges.
237→// Returns the first valid IP for pinning.
238→func (c *Client) resolveAndValidate(ctx context.Context, host string) (net.IP, error) {
239→	// If the host is already an IP literal, check it directly
240→	if ip := net.ParseIP(host); ip != nil {
241→		if isBlockedIP(ip) {
242→			return nil, fmt.Errorf("%w: %s", ErrBlockedIP, ip)
243→		}
244→		return ip, nil
245→	}
246→
247→	addrs, err := c.resolver.LookupIPAddr(ctx, host)
248→	if err != nil {
249→		return nil, fmt.Errorf("safefetch: dns lookup %q: %w", host, err)
250→	}
251→	if len(addrs) == 0 {
252→		return nil, fmt.Errorf("safefetch: dns lookup %q: no addresses", host)
253→	}
254→
255→	// ALL resolved IPs must be safe (attacker could use round-robin DNS)
256→	for _, addr := range addrs {
257→		if isBlockedIP(addr.IP) {
258→			return nil, fmt.Errorf("%w: %s resolves to %s", ErrBlockedIP, host, addr.IP)
259→		}
260→	}
261→
262→	return addrs[0].IP, nil
263→}
264→
265→// pinnedTransport returns an HTTP transport that connects to a specific IP,
266→// preventing TOCTOU between DNS resolution and connection.
267→func (c *Client) pinnedTransport(ip net.IP, port string) *http.Transport {
268→	if port == "" {
269→		port = "80"
270→	}
271→	addr := net.JoinHostPort(ip.String(), port)
272→
273→	return &http.Transport{
274→		DialContext: func(ctx context.Context, network, _ string) (net.Conn, error) {
275→			dialer := &net.Dialer{Timeout: 10 * time.Second}
276→			return dialer.DialContext(ctx, network, addr)
277→		},
278→		// Disable TLS for pinned transport — we connect by IP but the TLS
279→		// handshake uses the original hostname from the request.
280→		TLSHandshakeTimeout: 10 * time.Second,
281→		DisableKeepAlives:   true,
282→	}
283→}
284→
285→// isBlockedIP returns true if the IP falls in any blocked CIDR range.
286→// It normalizes IPv4-mapped IPv6 addresses (::ffff:x.x.x.x) to IPv4
287→// before checking, so that e.g. ::ffff:127.0.0.1 is correctly blocked.
288→func isBlockedIP(ip net.IP) bool {
289→	// Normalize IPv4-mapped IPv6 to plain IPv4
290→	if v4 := ip.To4(); v4 != nil {
291→		ip = v4
292→	}
293→	for _, n := range blockedNets {
294→		if n.Contains(ip) {
295→			return true
296→		}
297→	}
298→	return false
299→}
300→
301→func isRedirect(code int) bool {
302→	return code == 301 || code == 302 || code == 303 || code == 307 || code == 308
303→}
304→
305→func isAllowedContentType(ct string) bool {
306→	ct = strings.ToLower(strings.TrimSpace(ct))
307→	for _, prefix := range allowedContentTypes {
308→		if strings.HasPrefix(ct, prefix) {
309→			return true
310→		}
311→	}
312→	return false
313→}
